// Clef McpServer entry point
//
// Boots the McpServer concept with the devtools interface manifest.
// Auto-discovers all tools generated by the Bind MCP target and
// serves them over stdio.

import { bootMcpServer } from '../../handlers/ts/framework/mcp-server.handler.js';

const manifestPath = process.argv[2] || './examples/devtools/devtools.interface.yaml';
bootMcpServer(manifestPath);
